arguments.content:
:root {
    --bg-color: #0f172a;
    --card-bg: #1e293b;
    --text-primary: #f8fafc;
    --text-secondary: #94a3b8;
    --accent-color: #38bdf8;
    --accent-secondary: #818cf8;
    --success: #22c55e;
    --error: #ef4444;
    --border-color: #334155;
}

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    background-color: var(--bg-color);
    color: var(--text-primary);
    font-family: 'Inter', sans-serif;
    display: flex;
    justify-content: center;
    min-height: 100vh;
    padding: 2rem;
}

.container {
    width: 100%;
    max-width: 1200px;
}

header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2.5rem;
}

h1 {
    font-size: 2rem;
    font-weight: 600;
    background: linear-gradient(to right, var(--accent-color), var(--accent-secondary));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
}

#status-indicator {
    font-size: 0.875rem;
    padding: 0.25rem 0.75rem;
    border-radius: 9999px;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.status-online {
    background-color: rgba(34, 197, 94, 0.1);
    color: var(--success);
}

.status-offline {
    background-color: rgba(239, 68, 68, 0.1);
    color: var(--error);
}

main {
    display: block;
}

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(450px, 1fr));
    gap: 1.5rem;
}

@media (max-width: 600px) {
    .dashboard-grid {
        grid-template-columns: 1fr;
    }
}

.chart-card {
    background-color: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: 1rem;
    padding: 1.5rem;
    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
}

.chart-card h2 {
    font-size: 1.125rem;
    font-weight: 400;
    color: var(--text-secondary);
    margin-bottom: 1.5rem;
    text-align: center;
}

.chart-container {
    position: relative;
    height: 300px;
    width: 100%;
}

footer {
    margin-top: 3rem;
    text-align: center;
    color: var(--text-secondary);
    font-size: 0.875rem;
}

const API_URL = '/api/metrics';
const UPDATE_INTERVAL = 10000; // 10 seconds

// DOM Elements
const statusIndicator = document.getElementById('status-indicator');

// Configuration for charts
const MAX_DATA_POINTS = 20;

// State
let usageChart;
let tempChart;
let timeLabels = [];
let cpuUsageHistory = [];
let memoryUsageHistory = [];
let tempHistory = {}; // Stores history for each temperature sensor

/**
 * Initializes the charts
 */
function initCharts() {
    const usageCtx = document.getElementById('usageChart').getContext('2d');
    const tempCtx = document.getElementById('tempChart').getContext('2d');

    // Gradient for Usage Chart
    const cpuGradient = usageCtx.createLinearGradient(0, 0, 0, 400);
    cpuGradient.addColorStop(0, 'rgba(56, 189, 248, 0.4)');
    cpuGradient.addColorStop(1, 'rgba(56, 189, 248, 0)');

    const memGradient = usageCtx.createLinearGradient(0, 0, 0, 400);
    memGradient.addColorStop(0, 'rgba(129, 140, 248, 0.4)');
    memGradient.addColorStop(1, 'rgba(129, 140, 248, 0)');

    usageChart = new Chart(usageCtx, {
        type: 'line',
        data: {
            labels: timeLabels,
            datasets: [
                {
                    label: 'CPU Usage (%)',
                    data: cpuUsageHistory,
                    borderColor: '#38bdf8',
                    backgroundColor: cpuGradient,
                    fill: true,
                    tension: 0.4,
                    pointRadius: 0
                },
                {
                    label: 'Memory Usage (%)',
                    data: memoryUsageHistory,
                    borderColor: '#818cf8',
                    backgroundColor: memGradient,
                    fill: true,
                    tension: 0.4,
                    pointRadius: 0
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    labels: { color: '#94a3b8', font: { family: 'Inter' } }
                }
            },
            scales: {
                y: {
                    beginAtZero: true,
                    max: 100,
                    grid: { color: '#334155' },
                    ticks: { color: '#94a3b8' }
                },
                x: {
                    grid: { display: false },
                    ticks: { color: '#94a3b8' }
                }
            }
        }
    });

    tempChart = new Chart(tempCtx, {
        type: 'line',
        data: {
            labels: timeLabels,
            datasets: []
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    labels: { color: '#94a3b8', font: { family: 'Inter' } }
                }
            },
            scales: {
                y: {
                    grid: { color: '#334155' },
                    ticks: { color: '#94a3b8' }
                },
                x: {
                    grid: { display: false },
                    ticks: { color: '#94a3b8' }
                }
            }
        }
    });
}

/**
 * Updates the charts with new data
 * @param {Array<Object>} metrics - The list of metric objects
 */
function updateDashboard(metrics) {
    if (metrics.length === 0) return;

    // We take the latest metric entry
    const latest = metrics[metrics.length - 1];
    const timestamp = new Date().toLocaleTimeString();

    // Manage Time Labels
    timeLabels.push(timestamp);
    if (timeLabels.length > MAX_DATA_POINTS) {
        timeLabels.shift();
    }

    // Update Usage Data
    cpuUsageHistory.push(latest.cpu_percent);
    memoryUsageHistory.push(latest.memory_percent);
    if (cpuUsageHistory.length > MAX_DATA_POINTS) {
        cpuUsageHistory.shift();
        memoryUsageHistory.shift();
    }

    // Update Temperature Data
    const thermalData = latest.thermal_data || {};
    const sensorKeys = Object.keys(thermalData);

    // Ensure datasets exist for all sensors
    sensorKeys.forEach((key, index) => {
        let dataset = tempChart.data.datasets.find(ds => ds.label === key);

        if (!dataset) {
            const colors = ['#f87171', '#fb923c', '#fbbf24', '#4ade80', '#2dd4bf', '#38bdf8', '#818cf8', '#c084fc'];
            const color = colors[index % colors.length];

            dataset = {
                label: key,
                data: [],
                borderColor: color,
                backgroundColor: 'transparent',
                tension: 0.4,
                pointRadius: 0
            };
            tempChart.data.datasets.push(dataset);
            tempHistory[key] = [];
        }

        tempHistory[key].push(thermalData[key]);
        if (tempHistory[key].length > MAX_DATA_POINTS) {
            tempHistory[key].shift();
        }
        dataset.data = tempHistory[key];
    });

    // Clean up old datasets if sensors are removed
    tempChart.data.datasets = tempChart.data.datasets.filter(ds => {
        return sensorKeys.includes(ds.label);
    });

    // Clean up sensor history for removed detectors
    Object.keys(tempHistory).forEach(key => {
        if (!sensorKeys.includes(key)) {
            delete tempHistory[key];
        }
    });

    usageChart.update('none');
    tempChart.update('none');
}

/**
 * Fetches data from the API
 */
async function fetchData() {
    try {
        const response = await fetch(API_URL);
        if (!response.ok) throw new Error('Network response was not ok');

        const data = await response.json();
        updateDashboard(data);

        statusIndicator.textContent = 'Online';
        statusIndicator.className = 'status-online';
    } catch (error) {
        console.error('Error fetching data:', error);
        statusIndicator.textContent = 'Offline';
        statusIndicator.className = 'status-offline';
    }
}

// Entry point
document.addEventListener('DOMContentLoaded', () => {
    initCharts();
    fetchData();
    setInterval(fetchData, UPDATE_INTERVAL);
});
